```solidity
pragma solidity ^0.8.12;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract AwooToken is Ownable, ReentrancyGuard {
    uint256 public awooFeePercentage;
    bool public isActive;
    address public awooStudiosAccount;
    mapping(address => uint256) private _virtualBalance;
    mapping(address => bool) private _authorizedContracts;
    IERC20 public awooToken;

    event AuthorizedContractAdded(address indexed contractAddress);
    event AuthorizedContractRemoved(address indexed contractAddress);
    event VirtualAwooSpent(address indexed spender, uint256 amount);
    event Minted(address indexed account, uint256 amount);

    modifier onlyActive() {
        require(isActive, "Contract is not active");
        _;
    }

    modifier onlyAuthorized() {
        require(_authorizedContracts[msg.sender], "Not authorized");
        _;
    }

    constructor(
        uint256 _awooFeePercentage,
        address _awooStudiosAccount,
        address _awooTokenAddress
    ) {
        awooFeePercentage = _awooFeePercentage;
        awooStudiosAccount = _awooStudiosAccount;
        awooToken = IERC20(_awooTokenAddress);
        isActive = true;
    }

    function activate() external onlyOwner {
        isActive = true;
    }

    function deactivate() external onlyOwner {
        isActive = false;
    }

    function addAuthorizedContract(address contractAddress) external onlyOwner {
        require(contractAddress != address(0), "Invalid address");
        _authorizedContracts[contractAddress] = true;
        emit AuthorizedContractAdded(contractAddress);
    }

    function removeAuthorizedContract(address contractAddress) external onlyOwner {
        require(contractAddress != address(0), "Invalid address");
        _authorizedContracts[contractAddress] = false;
        emit AuthorizedContractRemoved(contractAddress);
    }

    function mint(address account, uint256 amount) external onlyAuthorized onlyActive {
        _virtualBalance[account] += amount;
        emit Minted(account, amount);
    }

    function deposit(uint256 amount) external nonReentrant {
        require(amount > 0, "Amount must be greater than zero");
        bool success = awooToken.transferFrom(msg.sender, address(this), amount);
        require(success, "TransferFrom failed");
    }

    function withdraw(uint256 amount) external nonReentrant {
        require(amount > 0, "Amount must be greater than zero");
        require(_virtualBalance[msg.sender] >= amount, "Insufficient virtual balance");
        _virtualBalance[msg.sender] -= amount;
        bool success = awooToken.transfer(msg.sender, amount);
        require(success, "Transfer failed");
    }

    function spendVirtualAwoo(uint256 amount) external onlyActive {
        require(amount > 0, "Amount must be greater than zero");
        require(_virtualBalance[msg.sender] >= amount, "Insufficient virtual balance");

        uint256 fee = (amount * awooFeePercentage) / 10000;
        uint256 netAmount = amount - fee;

        _virtualBalance[msg.sender] -= amount;
        awooToken.transfer(awooStudiosAccount, fee);
        awooToken.transfer(msg.sender, netAmount);

        emit VirtualAwooSpent(msg.sender, amount);
    }

    function balanceOf(address account) public view returns (uint256) {
        return _virtualBalance[account];
    }
}
```

